import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Signup() {
  // Ek hi object mein state rakhna acha hai
  const [formData, setFormData] = useState({ 
    username: '', 
    email: '', 
    password: '' 
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSignup = async (e) => {
    e.preventDefault();
    setLoading(true);

    // Debugging ke liye: console mein check karein data sahi hai ya nahi
    console.log("Sending data to backend:", formData);

    try {
      // Backend URL (Aapke uvicorn terminal se match hona chahiye)
      const response = await axios.post('http://127.0.0.1:8000/api/register', {
        username: formData.username,
        email: formData.email, 
        password: formData.password
      }, {
        headers: {
          'Content-Type': 'application/json'
        }
      });

      if (response.status === 200 || response.status === 201) {
        alert("Registration Successful! Ab aap login kar sakte hain."); 
        navigate('/login');
      }

    } catch (err) {
      console.error("Signup Error Details:", err);

      if (err.response) {
        // Backend (FastAPI) ne error bheja (e.g., Email already exists)
        const errorDetail = err.response.data.detail;
        alert("Backend Error: " + (typeof errorDetail === 'object' ? JSON.stringify(errorDetail) : errorDetail));
      } else if (err.request) {
        // Request toh gayi par response nahi mila (Connection/CORS issue)
        alert("Connectivity Issue: Backend server se response nahi mila. Check karein ki FastAPI server chalu hai.");
      } else {
        alert("Error: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="signup-page" style={{ padding: '50px', textAlign: 'center', backgroundColor: '#f4f7f6', minHeight: '100vh' }}>
      <div className="form-container" style={{ display: 'inline-block', background: 'white', padding: '40px', borderRadius: '15px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' }}>
        <h2 style={{ color: '#2c3e50', marginBottom: '10px' }}>Naya Account Banayein</h2>
        <p style={{ color: '#7f8c8d', marginBottom: '25px' }}>Grievance System mein register karein</p>

        <form onSubmit={handleSignup}>
          <input 
            type="text" 
            placeholder="Username" 
            value={formData.username}
            // Syntax check: Ensure username state is updated correctly
            onChange={(e) => setFormData({...formData, username: e.target.value})} 
            required 
            style={{padding: '12px', margin: '10px 0', width: '300px', borderRadius: '8px', border: '1px solid #ddd', outline: 'none'}} 
          /><br/>

          <input 
            type="email" 
            placeholder="Email Address" 
            value={formData.email}
            onChange={(e) => setFormData({...formData, email: e.target.value})} 
            required 
            style={{padding: '12px', margin: '10px 0', width: '300px', borderRadius: '8px', border: '1px solid #ddd', outline: 'none'}} 
          /><br/>

          <input 
            type="password" 
            placeholder="Password" 
            value={formData.password}
            onChange={(e) => setFormData({...formData, password: e.target.value})} 
            required 
            style={{padding: '12px', margin: '10px 0', width: '300px', borderRadius: '8px', border: '1px solid #ddd', outline: 'none'}} 
          /><br/>

          <button 
            type="submit" 
            disabled={loading}
            style={{ 
              backgroundColor: loading ? '#bdc3c7' : '#2ecc71', 
              color: 'white', 
              padding: '14px 0', 
              width: '100%',
              border: 'none', 
              borderRadius: '8px',
              cursor: loading ? 'not-allowed' : 'pointer', 
              marginTop: '20px',
              fontSize: '16px',
              fontWeight: 'bold'
            }}
          >
            {loading ? "Process ho raha hai..." : "Register Now"}
          </button>
        </form>

        <p style={{ marginTop: '25px', fontSize: '14px', color: '#34495e' }}>
          Pehle se account hai? <span style={{ color: '#3498db', cursor: 'pointer', fontWeight: 'bold' }} onClick={() => navigate('/login')}>Login karein</span>
        </p>
      </div>
    </div>
  );
}

export default Signup;
